Use greedy insertion with cheapest marginal cost among all feasible assign slots, fallback to earliest empty assign if none feasible, maintain feasibility without breaking the outer loop.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx     int
		addCost float64
	}
	for jj := range oris {
		best := candidate{idx: -1, addCost: 1e18}
		foundEmpty := false
		for ii := 0; ii < MAXASSIGNS; ii++ {
			tmpAssign := dispatch.Assigns[ii]
			ok := tmpAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok && tmpAssign.Cost >= 0 {
				marginal := tmpAssign.Cost - dispatch.Assigns[ii].Cost
				if marginal < best.addCost || (!foundEmpty && ii >= dispatch.AssignsLen) {
					best.idx = ii
					best.addCost = marginal
					if ii >= dispatch.AssignsLen {
						foundEmpty = true
					}
				}
				tmpAssign.RemoveShip(total_ship + jj)
				tmpAssign.GenRoute()
			} else if ok {
				tmpAssign.RemoveShip(total_ship + jj)
				tmpAssign.GenRoute()
			}
		}
		if best.idx == -1 {
			for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
				tmpAssign := dispatch.Assigns[ii]
				if tmpAssign.StationsLen == 0 {
					ok := tmpAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
					if ok && tmpAssign.Cost >= 0 {
						best.idx = ii
						break
					} else if ok {
						tmpAssign.RemoveShip(total_ship + jj)
						tmpAssign.GenRoute()
					}
				}
			}
		}
		if best.idx != -1 {
			dispatch.Assigns[best.idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[best.idx].GenRoute()
			if best.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = best.idx + 1
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

