func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx        int
		costInc    float64
		isExisting bool
	}
	const candidateSize = 5
	orderCount := len(oris)
	for oIdx := 0; oIdx < orderCount; oIdx++ {
		bestCand := cand{idx: -1, costInc: 1e100, isExisting: false}
		candidates := make([]cand, 0, candidateSize*2)
		ori := oris[oIdx]
		des := dess[oIdx]
		shipID := total_ship + oIdx
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					inc := newCost - oldCost
					if inc < 0 {
						inc = 0
					}
					candidates = append(candidates, cand{idx: i, costInc: inc, isExisting: true})
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
		}
		for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
			tempAssign := dispatch.Assigns[i]
			ok := tempAssign.AddShip(shipID, ori, des)
			if ok {
				tempAssign.GenRoute()
				if tempAssign.Cost >= 0 {
					candidates = append(candidates, cand{idx: i, costInc: tempAssign.Cost, isExisting: false})
				}
			}
		}
		if len(candidates) > 0 {
			sort.SliceStable(candidates, func(a, b int) bool {
				return candidates[a].costInc < candidates[b].costInc
			})
			limit := candidateSize
			if limit > len(candidates) {
				limit = len(candidates)
			}
			selected := candidates[0]
			if selected.isExisting {
				dispatch.Assigns[selected.idx].AddShip(shipID, ori, des)
				dispatch.Assigns[selected.idx].GenRoute()
			} else {
				idx := selected.idx
				if idx == dispatch.AssignsLen {
					dispatch.Assigns[idx] = Assign{}
					dispatch.Assigns[idx].AddShip(shipID, ori, des)
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[idx] = Assign{}
					dispatch.Assigns[idx].AddShip(shipID, ori, des)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx] = Assign{}
				dispatch.Assigns[idx].AddShip(shipID, ori, des)
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
